const input = $input.first().json.body || $input.first().json;
const question = String(input.question || '').trim();
const fileUrl = String(input.fileUrl || '').trim();
return [{
  json: {
    ...input,
    question,
    fileUrl,
    patientContext: input.patientContext && typeof input.patientContext === 'object' ? input.patientContext : { age: 60, sex: 'masculino' },
    topK: Math.min(Math.max(Number(input.topK || 6), 1), 12),
    category: input.category || 'prospecto',
    valid: Boolean(question) && Boolean(fileUrl),
    startedAtMs: Date.now()
  }
}];

const current = $input.first().json;
const jobId = current?.job?.id || current?.id;
return [{ json: { jobId, validJob: Boolean(jobId) } }];

function slugify(text) {
  return String(text || 'doc')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '') || 'doc';
}

function splitMarkdownSections(markdown) {
  const clean = String(markdown || '').replace(/\r/g, '').trim();
  if (!clean) return [];
  const lines = clean.split('\n');
  const sections = [];
  let currentTitle = 'Contenido principal';
  let buffer = [];

  const flush = () => {
    const text = buffer.join('\n').trim();
    if (!text) return;
    sections.push({ slug: slugify(currentTitle), title: currentTitle, text });
    buffer = [];
  };

  for (const rawLine of lines) {
    const line = rawLine.trimEnd();
    const heading = line.match(/^#{1,6}\s+(.+)$/);
    if (heading) {
      flush();
      currentTitle = heading[1].trim();
      continue;
    }
    buffer.push(line);
  }
  flush();

  return sections.length
    ? sections
    : clean.split(/\n\s*\n+/).map((block, idx) => ({ slug: `bloque-${idx + 1}`, title: `Bloque ${idx + 1}`, text: block.trim() })).filter((section) => section.text);
}

function anonymize(text) {
  const patterns = [
    { pattern: /\b\d{1,2}\.\d{3}\.\d{3}\b/g, replacement: '[DNI]' },
    { pattern: /\b\d{7,8}\b/g, replacement: '[DNI]' },
    { pattern: /\b\d{2}-\d{7,8}-\d\b/g, replacement: '[CUIT]' },
    { pattern: /\b(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})\b/gi, replacement: '[FECHA]' },
    { pattern: /\b[\w.-]+@[\w.-]+\.\w+\b/gi, replacement: '[EMAIL]' },
    { pattern: /\b(Sr\.?|Sra\.?|Dr\.?|Dra\.?)\s+[A-Z][a-z]+ [A-Z][a-z]+\b/g, replacement: '[NOMBRE]' }
  ];

  let output = String(text || '');
  for (const { pattern, replacement } of patterns) output = output.replace(pattern, replacement);
  return output;
}

const data = $input.first().json;
const markdown = anonymize(data.markdown || data.md || '');
const originalText = anonymize(data.text || data.txt || '');
const sections = splitMarkdownSections(markdown || originalText);

return [{
  json: {
    ...data,
    anonymizedMarkdown: markdown,
    anonymizedText: originalText,
    documents: [{
      docId: slugify(data.documentTitle || 'documento-parseado'),
      title: data.documentTitle || 'Documento parseado desde LlamaCloud',
      category: data.category || 'prospecto',
      version: new Date().toISOString().slice(0, 10),
      tags: ['parseado', 'clinico'],
      sections
    }],
    parseMeta: {
      pageCount: Array.isArray(data.json) ? data.json.length : 1,
      sourceFormat: String(data.fileUrl || '').split('.').pop() || 'unknown'
    }
  }
}];

function stripAccents(text) {
  return String(text || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function normalize(text) {
  const replacements = {
    panza: 'abdominal',
    barriga: 'abdominal',
    estomago: 'abdominal',
    nausea: 'nauseas',
    vomitos: 'vomito',
    gastricas: 'gastrointestinal',
    gastrica: 'gastrointestinal',
    anciano: 'adulto',
    geriatrico: 'adulto'
  };

  const cleaned = stripAccents(text)
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return cleaned ? cleaned.split(' ').map((token) => replacements[token] || token) : [];
}

function buildVector(text, dims = 64) {
  const vec = Array(dims).fill(0);
  for (const token of normalize(text)) {
    let hash = 0;
    for (let i = 0; i < token.length; i++) {
      hash = ((hash << 5) - hash) + token.charCodeAt(i);
      hash |= 0;
    }
    const idx = Math.abs(hash) % dims;
    vec[idx] += 1;
  }
  const norm = Math.sqrt(vec.reduce((acc, value) => acc + (value * value), 0)) || 1;
  return vec.map((value) => Number((value / norm).toFixed(6)));
}

function cosine(a, b) {
  let sum = 0;
  for (let i = 0; i < Math.max(a.length, b.length); i++) sum += (a[i] || 0) * (b[i] || 0);
  return sum;
}

function overlapScore(queryText, candidateText) {
  const q = new Set(normalize(queryText));
  const c = new Set(normalize(candidateText));
  if (!q.size) return 0;
  let hits = 0;
  for (const token of q) if (c.has(token)) hits += 1;
  return hits / q.size;
}

function chunkDocuments(documents) {
  const chunks = [];
  for (const doc of documents) {
    for (const [sectionIndex, section] of (doc.sections || []).entries()) {
      const rawSentences = String(section.text || '').split(/(?<=[.!?])\s+/).map((sentence) => sentence.trim()).filter(Boolean);
      const sentences = rawSentences.length ? rawSentences : [String(section.text || '').trim()].filter(Boolean);
      let buffer = [];
      let chunkCounter = 0;

      const flush = () => {
        const text = buffer.join(' ').trim();
        if (!text) return;
        chunkCounter += 1;
        chunks.push({
          chunkId: `${doc.docId}-${section.slug || ('sec' + (sectionIndex + 1))}-c${chunkCounter}`,
          docId: doc.docId,
          title: doc.title,
          category: doc.category || 'prospecto',
          version: doc.version || 'v1',
          section: section.title || `Seccion ${sectionIndex + 1}`,
          sectionSlug: section.slug || `sec-${sectionIndex + 1}`,
          text,
          tags: doc.tags || [],
          sourceLabel: `${doc.title} / ${section.title || ('Seccion ' + (sectionIndex + 1))}`
        });
        buffer = [];
      };

      for (const sentence of sentences) {
        const current = buffer.join(' ');
        if (current && (current.length + sentence.length + 1) > 320) flush();
        buffer.push(sentence);
      }
      flush();
    }
  }
  return chunks;
}

const current = $input.first().json;
const chunks = chunkDocuments(current.documents || []);
const embeddedChunks = chunks.map((chunk) => {
  const textForEmbedding = [chunk.title, chunk.section, ...(chunk.tags || []), chunk.text].join(' ');
  return { ...chunk, textForEmbedding, vector: buildVector(textForEmbedding) };
});

const patientBits = Object.entries(current.patientContext || {}).map(([key, value]) => `${key}: ${value}`).join(', ');
const queryText = [current.question, patientBits].filter(Boolean).join(' | ');
const queryVector = buildVector(queryText);
const scored = embeddedChunks
  .map((chunk) => {
    const semanticScore = cosine(queryVector, chunk.vector);
    const lexicalScore = overlapScore(queryText, chunk.textForEmbedding);
    const score = Number(((semanticScore * 0.72) + (lexicalScore * 0.24)).toFixed(4));
    return { ...chunk, semanticScore: Number(semanticScore.toFixed(4)), lexicalScore: Number(lexicalScore.toFixed(4)), score };
  })
  .filter((chunk) => chunk.score > 0.05)
  .sort((a, b) => b.score - a.score);

const retrievedChunks = scored.slice(0, current.topK || 6);
const topScore = retrievedChunks[0] ? retrievedChunks[0].score : 0;

return [{
  json: {
    ...current,
    chunks,
    embeddedChunks,
    queryText,
    retrievedChunks,
    retrieval: {
      topK: current.topK || 6,
      returned: retrievedChunks.length,
      topScore: Number(topScore.toFixed(4)),
      minScoreThreshold: 0.18,
      scopeUsed: 'current-document',
      availableChunks: embeddedChunks.length
    },
    evidenceSufficient: retrievedChunks.length > 0 && topScore >= 0.18
  }
}];

function extractJson(t) {
  if (!t) return null;
  if (typeof t === 'object') return t;
  try { return JSON.parse(t); } catch (e) {}
  const cleaned = String(t).replace(/^```json/i, '').replace(/```$/i, '').trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (e) {}
  }
  return null;
}

const current = $input.first().json;
const previous = $('✂️ Chunking + Retrieval').first().json;
const retrievedChunks = previous.retrievedChunks || [];
const retrieval = previous.retrieval || {};
const patientContext = previous.patientContext || {};
const parseMeta = previous.parseMeta || {};
const draft = extractJson(current.llmRaw) || {};
const sourceMap = new Map(retrievedChunks.map((chunk) => [chunk.chunkId, chunk]));
const errors = [];

if (!draft.answer || typeof draft.answer !== 'string' || !draft.answer.trim()) errors.push('missing-answer');
if (!Array.isArray(draft.sources) || draft.sources.length === 0) errors.push('missing-sources');

const groundedSources = Array.isArray(draft.sources)
  ? draft.sources.map((source) => sourceMap.get(source.chunkId)).filter(Boolean).map((chunk) => ({
      chunkId: chunk.chunkId,
      docId: chunk.docId,
      title: chunk.title,
      section: chunk.section,
      score: chunk.score,
      evidence: String(chunk.text || '').slice(0, 180)
    }))
  : [];

if (groundedSources.length === 0) errors.push('sources-not-grounded');

const fallbackUsed = errors.length > 0;
const finalSources = fallbackUsed
  ? retrievedChunks.slice(0, 3).map((chunk) => ({
      chunkId: chunk.chunkId,
      docId: chunk.docId,
      title: chunk.title,
      section: chunk.section,
      score: chunk.score,
      evidence: String(chunk.text || '').slice(0, 180)
    }))
  : groundedSources.slice(0, 3);

return [{
  json: {
    success: true,
    question: previous.question,
    fileUrl: $('✅ Validar input').first().json.fileUrl,
    patientContext,
    answer: fallbackUsed ? 'No se pudo validar una sintesis trazable del modelo. Dejo los fragmentos con mejor score para revision humana. Este flujo funciona como busqueda documental, no como recomendacion medica.' : draft.answer.trim(),
    sources: finalSources,
    confidence: fallbackUsed ? 'baja' : (['alta', 'media', 'baja'].includes(draft.confidence) ? draft.confidence : 'media'),
    fallbackUsed,
    fallbackReason: fallbackUsed ? errors[0] : null,
    requiresHumanReview: true,
    retrieval,
    parseMeta,
    log: {
      event: 'llamacloud_rag_e2e',
      ts: new Date().toISOString(),
      latencyMs: Math.max(Date.now() - (previous.startedAtMs || Date.now()), 0),
      returnedChunks: retrieval ? retrieval.returned : 0,
      topScore: retrieval ? retrieval.topScore : 0,
      fallbackUsed,
      fallbackReason: fallbackUsed ? errors[0] : null
    }
  }
}];

const current = $input.first().json;
return [{
  json: {
    success: true,
    question: current.question,
    fileUrl: current.fileUrl,
    patientContext: current.patientContext,
    answer: 'No se hallo evidencia suficiente dentro del documento parseado para responder con trazabilidad. Reformula la consulta o deriva a revision humana. Este flujo no reemplaza evaluacion profesional.',
    sources: (current.retrievedChunks || []).slice(0, 3).map((chunk) => ({
      chunkId: chunk.chunkId,
      docId: chunk.docId,
      title: chunk.title,
      section: chunk.section,
      score: chunk.score,
      evidence: String(chunk.text || '').slice(0, 180)
    })),
    confidence: 'baja',
    fallbackUsed: true,
    fallbackReason: 'insufficient-evidence',
    requiresHumanReview: true,
    retrieval: current.retrieval,
    parseMeta: current.parseMeta,
    log: {
      event: 'llamacloud_rag_e2e',
      ts: new Date().toISOString(),
      latencyMs: Math.max(Date.now() - (current.startedAtMs || Date.now()), 0),
      returnedChunks: current.retrieval ? current.retrieval.returned : 0,
      topScore: current.retrieval ? current.retrieval.topScore : 0,
      fallbackUsed: true,
      fallbackReason: 'insufficient-evidence'
    }
  }
}];
